  ('dietitian-moex-00496', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列有關灌食配方的敘述，何者錯誤？', '["灌食配方的滲透壓由某些特定營養素分子的大小與數量決定，一般商業均衡聚合配方（1 kcal/mL）的滲透 壓介於300～500 mOsm/L之間", "單素配方（modular formula）不適合管灌病人單獨使用", "元素飲食（monomeric formula）由基本營養素分子所組成，易消化吸收，也可以靜脈注射方式供應", "灌食配方中氮：總熱量（nitrogen:total calorie）比例為1：150，表示該配方的蛋白質占總熱量的比例 為16.7%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00497', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關神經性厭食症（anorexia nervosa）病人的營養治療，下列敘述何者錯誤？', '["後期體重增加階段，建議熱量處方：70～100大卡／公斤體重／天", "refeeding syndrome的風險主要取決於熱量攝取和體重增加的速度", "蛋白質宜占總熱量15～20%", "refeeding syndrome高風險病人可預防性補充磷、鎂和鉀"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00498', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '體脂肪百分比在下列那個時期最高？', '["0～6個月", "7～12個月", "1～3歲", "4～6歲"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00499', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關脂肪細胞的增生（hyperplasia）和肥大（hypertrophy），下列敘述何者錯誤？', '["不論纖瘦或肥胖兒童進入青春期階段後，脂肪細胞數量均會增加", "成人會發生脂肪細胞肥大，但不會有脂肪細胞增生", "任何年齡層，當空間許可的狀況下，脂肪細胞肥大可以增加至1,000倍", "adiposity rebound的現象若提早至五歲半以前發生，可預測成人階段發生肥胖的機率較高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00500', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '依據美國運動醫學會及美國國家骨質疏鬆基金會對於預防骨質疏鬆及骨折的飲食和運動建議，下列何者錯 誤？', '["每週3～5次負重（weight-bearing）有氧運動", "必要時應考慮使用補充劑達到維生素D攝取建議量", "每週至少2次游泳訓練", "避免高鈉飲食"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": "006b7e686bce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
